import{_ as n,o as t,c as a,a0 as i}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"Bán hàng","description":"","frontmatter":{"title":"Bán hàng","sidebar_position":1},"headers":[],"relativePath":"selling.md","filePath":"selling.md"}'),o={name:"selling.md"};function c(g,h,e,r,u,l){return t(),a("div",null,[...h[0]||(h[0]=[i('<h1 id="ban-hang" tabindex="-1">Bán hàng <a class="header-anchor" href="#ban-hang" aria-label="Permalink to &quot;Bán hàng&quot;">​</a></h1><p>Mô-đun Bán hàng trong ABNERP là trung tâm quản lý toàn bộ quy trình bán hàng, từ khi tiếp cận khách hàng, tạo báo giá, xử lý đơn hàng cho đến khi xuất hóa đơn và theo dõi thanh toán. Đây là một trong những mô-đun cốt lõi, tích hợp chặt chẽ với các mô-đun Kho, Kế toán và Sản xuất.</p><h2 id="bao-gia-quotation" tabindex="-1">Báo giá (Quotation) <a class="header-anchor" href="#bao-gia-quotation" aria-label="Permalink to &quot;Báo giá (Quotation)&quot;">​</a></h2><p>Báo giá là bước đầu tiên trong quy trình bán hàng. Bạn có thể tạo báo giá từ cơ hội bán hàng hoặc trực tiếp cho khách hàng. Báo giá bao gồm danh sách sản phẩm/dịch vụ, số lượng, đơn giá, chiết khấu và thuế. ABNERP hỗ trợ tạo nhiều phiên bản báo giá, cho phép theo dõi lịch sử thay đổi và so sánh giữa các phiên bản. Khi khách hàng chấp nhận, báo giá có thể được chuyển đổi thành đơn bán hàng chỉ với một thao tác.</p><h2 id="đon-ban-hang-sales-order" tabindex="-1">Đơn bán hàng (Sales Order) <a class="header-anchor" href="#đon-ban-hang-sales-order" aria-label="Permalink to &quot;Đơn bán hàng (Sales Order)&quot;">​</a></h2><p>Đơn bán hàng là cam kết chính thức giữa doanh nghiệp và khách hàng. Sau khi được tạo, đơn bán hàng sẽ kích hoạt các quy trình liên quan như kiểm tra tồn kho, đặt hàng sản xuất (nếu cần), và lên lịch giao hàng. Hệ thống tự động cập nhật trạng thái đơn hàng qua từng bước: Chờ xác nhận, Đang xử lý, Đã giao một phần, Đã giao đủ, và Hoàn thành.</p><h2 id="hoa-đon-ban-hang-sales-invoice" tabindex="-1">Hóa đơn bán hàng (Sales Invoice) <a class="header-anchor" href="#hoa-đon-ban-hang-sales-invoice" aria-label="Permalink to &quot;Hóa đơn bán hàng (Sales Invoice)&quot;">​</a></h2><p>Hóa đơn bán hàng được tạo từ đơn bán hàng đã giao hoặc một phần đã giao. ABNERP hỗ trợ nhiều định dạng hóa đơn theo quy định của cơ quan thuế. Hóa đơn ghi nhận doanh thu và công nợ phải thu, đồng thời cập nhật số dư tài khoản kế toán tương ứng. Bạn có thể theo dõi trạng thái thanh toán, in ấn, gửi email hóa đơn cho khách hàng trực tiếp từ hệ thống.</p><h2 id="khach-hang-customer" tabindex="-1">Khách hàng (Customer) <a class="header-anchor" href="#khach-hang-customer" aria-label="Permalink to &quot;Khách hàng (Customer)&quot;">​</a></h2><p>Danh sách khách hàng được quản lý tập trung với đầy đủ thông tin: tên, mã số thuế, địa chỉ, thông tin liên hệ, nhóm khách hàng, và lịch sử giao dịch. ABNERP cho phép phân loại khách hàng theo nhiều tiêu chí khác nhau, hỗ trợ việc áp dụng chính sách giá và chiết khấu linh hoạt cho từng nhóm.</p><h2 id="gia-pricing" tabindex="-1">Giá (Pricing) <a class="header-anchor" href="#gia-pricing" aria-label="Permalink to &quot;Giá (Pricing)&quot;">​</a></h2><p>Hệ thống giá của ABNERP rất linh hoạt. Bạn có thể thiết lập bảng giá cho từng khách hàng hoặc nhóm khách hàng, áp dụng giá theo số lượng, theo thời vụ, hoặc theo chương trình khuyến mãi. Giá bán có thể được tính tự động dựa trên giá vốn và tỷ lệ lợi nhuận mong muốn.</p><h2 id="chiet-khau-discounts" tabindex="-1">Chiết khấu (Discounts) <a class="header-anchor" href="#chiet-khau-discounts" aria-label="Permalink to &quot;Chiết khấu (Discounts)&quot;">​</a></h2><p>ABNERP hỗ trợ nhiều cấp độ chiết khấu: chiết khấu theo dòng sản phẩm, chiết khấu theo tổng hóa đơn, và chiết khấu theo chương trình khuyến mãi. Bạn có thể thiết lập quy tắc chiết khấu tự động dựa trên khách hàng, sản phẩm, số lượng hoặc thời gian.</p><h2 id="thue-taxes" tabindex="-1">Thuế (Taxes) <a class="header-anchor" href="#thue-taxes" aria-label="Permalink to &quot;Thuế (Taxes)&quot;">​</a></h2><p>Mô-đun Bán hàng tích hợp đầy đủ các loại thuế như thuế GTGT, thuế tiêu thụ đặc biệt, và các loại thuế khác. Cấu hình thuế linh hoạt cho phép thiết lập nhiều mức thuế suất khác nhau, áp dụng cho từng sản phẩm hoặc nhóm sản phẩm. Hệ thống tự động tính toán thuế trên hóa đơn và báo cáo thuế định kỳ.</p>',16)])])}const d=n(o,[["render",c]]);export{p as __pageData,d as default};
